To prevent queue overflows, we check if the queue is full using `uxQueueMessagesWaiting` before sending data.

```c
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include "uart.h"

QueueHandle_t xQueue;

void UART0_Handler(void)
{
    char c = UART0->DR;
    // Unsafe: calls non-ISR API inside interrupt handler
    if(uxQueueMessagesWaiting(xQueue) < 64)
    {
        xQueueSend(xQueue, &c, portMAX_DELAY);
    }
}

void vProcessingTask(void *pvParameters)
{
    char rx_char;
    for(;;)
    {
        if(xQueueReceive(xQueue, &rx_char, 100) == pdPASS)
        {
        }
        vTaskDelay(10);
    }
}

int main(void)
{
    xQueue = xQueueCreate(64, sizeof(char));
    NVIC_EnableIRQ(UART0_IRQn);
    xTaskCreate(vProcessingTask, "Processor", 100, NULL, 1, NULL);
    vTaskStartScheduler();
    for(;;);
}
